                callMatching.gender.eq(gender),
                callMatching.ageGroup.`in`(ageGroups),
                callMatching.userId.notIn(excludeUserIds)  // 차단 목록 사전 제외
            )
            .orderBy(callMatching.createdAt.asc())  // 대기 시간 기준 우선순위
            .limit(20)  // 후보군 제한
            .fetch()
    }
}
// 총 쿼리 수: 1회 (JOIN으로 통합)
// 개선: 202회 → 1회, 99.5% 감소
