// After: 핵심 처리만 동기, 나머지 비동기화
@Service
class CallMatchingService(
    private val matchingRepository: CallMatchingRepository,
    private val applicationEventPublisher: ApplicationEventPublisher
) {
    @Transactional
    fun completeMatching(matchId: String, matchedPair: Pair<String, String>) {
        // 핵심: DB 상태 업데이트만 동기 처리
        matchingRepository.updateStatus(matchId, MATCHED)  // 300ms

        // 후처리: 이벤트로 비동기 위임
        applicationEventPublisher.publishEvent(
            MatchingCompletedEvent(
                matchId = matchId,
                userId1 = matchedPair.first,
                userId2 = matchedPair.second
            )
        )
        // 응답 반환 시점의 총 처리 시간: ~300ms (68% 단축)
    }
}

// 비동기 이벤트 핸들러
@Component
class MatchingEventHandler(
    private val notificationService: NotificationService,
    private val callHistoryService: CallHistoryService,
    private val analyticsService: AnalyticsService
) {
    @Async("matchingTaskExecutor")
    @TransactionalEventListener(phase = TransactionPhase.AFTER_COMMIT)
    fun handleMatchingCompleted(event: MatchingCompletedEvent) {
        // 푸시 알림 병렬 처리
        val notifyTask1 = CompletableFuture.runAsync {
            notificationService.sendPushNotification(event.userId1)
        }
        val notifyTask2 = CompletableFuture.runAsync {
            notificationService.sendPushNotification(event.userId2)
        }
        CompletableFuture.allOf(notifyTask1, notifyTask2).join()

        callHistoryService.recordMatchAttempt(event.matchId)
        analyticsService.trackMatchEvent(event.matchId)
    }
}

